VALUES
  ('heelevel3-d0d1b9a2-moex-00245', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列何者最不可能是查核人員兼採控制測試及證實程序之併用方式查核策略的原因？', '["查核人員預期受查者之內部控制制度設計良好，且能有效運作", "今年度交易大多為例行性交易，且受查者對於處理例行性交易有良好的控制程序", "為進一步瞭解內部控制並執行控制測試之成本，大於因而執行較少之證實測試可節省之成本", "受查者資訊系統已高度電腦化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00246', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '依據審計準則580號「書面聲明」之規定，下列敘述何者錯誤？', '["書面聲明是必要查核證據，受查者不提供或認為管理階層所出具之書面聲明不可靠時，會 計師應對財務報表出具無法表示意見之查核報告", "於某些情況下，查核人員可接受管理階層於書面聲明中使用「就本公司所知」之限制性文字", "為所要求書面聲明之目的，查核人員可與管理階層溝通顯然微小門檻", "管理階層對已履行其編製財務報表責任之書面聲明不可敘明「除某重大事項未遵循適用之 財務報導架構外，其已依該架構編製財務報表」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
