  ('heelevel3-d0d1b9a2-moex-00248', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '公司送交股東的年報中，除了財務報表及查核報告之外，尚包括其他資訊。有關查核人員對 「其他資訊」責任之敘述，下列何者正確？', '["查核人員無義務閱讀「其他資訊」", "查核人員無義務查證「其他資訊」，但仍應閱讀「其他資訊」以確定其與財務報表是否有重 大的不一致", "查核人員應擴大查核程序，以驗證「其他資訊」", "查核人員應於查核報告的其他事項段，述明「其他資訊未經查核」或「查核報告未涵蓋其 他資訊」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00249', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列查核程序，何者適合於查核訴訟與索賠事項之完整性聲明？①將財務報表與期後最近之', '["查閱至外勤工作結束日止之董事會及其他重要會議之議事錄", "複核有關賠償損失項目", "向受查者管理階層取得未決法律案件清單", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00250', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列何種情形可能增加樣本量？', '["可接受之非抽樣風險提高", "母體大小增加", "查核人員要求之信賴水準降低", "可容忍不實表達提高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00251', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列何者最不可能導致關係人之關係及交易有較高之重大不實表達風險之情況？', '["資訊系統可能無法有效辨認或彙總受查者與其關係人間之交易及餘額", "企業於正常營運下之關係人交易", "管理階層可能未知悉所有關係人之關係及交易之存在", "管理階層共謀、隱匿及操縱"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00252', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '有關財務報導舞弊風險因子，下列何者非屬誘因或壓力？', '["管理階層透過年報、法人說明會或媒體發布過度樂觀之預期", "管理階層為稅負之考量，欲以不當方式降低盈餘", "管理階層對股價或獲利趨勢之維持或提高過度關心", "管理階層屢次利用重大性之判斷，試圖為不適當之會計處理作解釋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00253', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '依審計準則505號「外部函證」之規定，設計詢證函內容時宜考量之因素最不可能包括下列何 者？', '["以往查核或類似案件之經驗", "替代查核程序之性質", "管理階層對受函證者回覆予查核人員之授權或鼓勵", "受函證者能否確認或提供所要求之資訊"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00254', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-112-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '有關存貨盤點之敘述，下列何者錯誤？', '["實務上，存貨盤點可能非於財務報導期間結束日執行", "查核人員觀察存貨之盤點，其主要目的在驗證財務報表五大聲明中的完整性", "查核人員參與存貨盤點時，檢查存貨可確認存貨之存在，並辨認過時、損壞或陳舊之存貨", "就查核目的而言，非於財務報導期間結束日執行存貨盤點是否適當，取決於受查者對存貨 變動控制之設計、付諸實行及維持之有效性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
